import { TZDateMini } from '@date-fns/tz';
import { forwardRef } from 'react';
import { useIntl } from 'react-intl';

import * as styles from './TimeframeSelectorOverlay.sty.js';
import { TimeframeSelectorOverlayFooter } from './TimeframeSelectorOverlayFooter.js';
import { FocusScope } from '../../../../core/components/focus-scope/FocusScope.js';
import { OverlayContainer } from '../../../../core/components/OverlayContainer.js';
import { useOverlayStacking } from '../../../../core/hooks/useOverlayStacking.js';
import { useRovingFocus } from '../../../../core/hooks/useRovingFocus.js';
import { OverlayStackingProvider } from '../../../../core/providers/OverlayStackingProvider.js';
import { useTimeframeSelectorStore } from '../../../../core/time/timeframeStore/useTimeframeStore.js';
import type { MaskingProps } from '../../../../core/types/masking-props.js';
import type { WithChildren } from '../../../../core/types/with-children.js';
import { useDateTimeFormat } from '../../../../forms/date-time-picker/hooks/useDateTimeFormat.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import type { OverlayTriggerState } from '../../../../overlays/hooks/useOverlay.js';
import { DismissButton } from '../../../../overlays/hooks/useOverlay.js';
import type { OverlayProps } from '../../../../overlays/hooks/useOverlayWithTrigger.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../../constants/timeframeSelectorMessages.js';
import type { TimeframeSelectorProps } from '../../TimeframeSelector.types.js';
import { CustomTimeframeSelector } from '../custom-timeframe-selector/CustomTimeframeSelector.js';
import { Presets } from '../presets/Presets.js';
import { RecentTimeframes } from '../presets/RecentTimeframes.js';

//#region Typings
interface TimeframeSelectorOverlayProps
  extends WithChildren,
    MaskingProps,
    Pick<TimeframeSelectorProps, 'clearable'> {
  /** The props of the overlay. */
  overlayProps: OverlayProps['overlayProps'];
  /** The state of the overlay. */
  overlayClose: OverlayTriggerState['close'];
}
//#endregion

function getMaxWidth(toParts: (date: Date) => Intl.DateTimeFormatPart[]) {
  const placeholderFromOrToParts = toParts(new TZDateMini()).map(
    (part: Intl.DateTimeFormatPart) => {
      if (part.type === 'dayPeriod') {
        return 'AM/PM';
      }

      return part.value;
    },
  );
  const placeholderFromOrTo = placeholderFromOrToParts.join('');
  const placeholdersNumberOfChars = 2 * placeholderFromOrTo.length;
  const surroundingSpace = 22; // this is an approximation in ch units of the space around the placeholders (including the inline padding inside each placeholder part)

  return `${
    placeholdersNumberOfChars * 1.05 + // try to compensate for the ch unit being calculated for "0" instead of a placeholder char, which needs slightly more width
    surroundingSpace
  }ch`;
}

/**
 * Relative Timeframe Selector Overlay component
 */
export const TimeframeSelectorOverlay = forwardRef<
  HTMLDivElement,
  TimeframeSelectorOverlayProps
>((props, forwardedRef) => {
  const {
    overlayProps,
    /* eslint-disable @typescript-eslint/no-deprecated */
    clearable,
    children,
    overlayClose,
    'data-dtrum-mask': dataDtrumMask,
    'data-dtrum-allow': dataDtrumAllow,
  } = props;
  const intl = useIntl();
  const {
    trapFocus,
    style: overlayPropsStyle,
    ...remainingOverlayProps
  } = overlayProps;
  const overlayContainerProps = useOverlayStacking(undefined, 'overlay');

  const precision = useTimeframeSelectorStore((state) => state.precision);
  const { toParts } = useDateTimeFormat('datetime', precision);

  const { containerRef } = useRovingFocus<HTMLDivElement>({
    initialIndex: 0,
    direction: 'vertical',
    focusableChildrenSelector: "[role='option'][aria-disabled='false']",
  });

  return (
    <OverlayContainer
      {...overlayContainerProps}
      data-dtrum-mask={dataDtrumMask}
      data-dtrum-allow={dataDtrumAllow}
    >
      <OverlayStackingProvider>
        <FocusScope autoFocus>
          <Flex
            ref={forwardedRef}
            gap={4}
            flexDirection="column"
            padding={4}
            className={styles.wrapper}
            style={{
              ...overlayPropsStyle,
              width: getMaxWidth(toParts),
              maxHeight: `min(${overlayPropsStyle?.maxHeight}, 600px)`,
            }}
            aria-label={intl.formatMessage(
              TIMEFRAME_SELECTOR_MESSAGES.overlayContainer,
            )}
            {...remainingOverlayProps}
          >
            <CustomTimeframeSelector />
            <Flex
              ref={containerRef}
              gap={4}
              paddingLeft={0}
              paddingRight={0}
              flexDirection="column"
              className={styles.scrollContainer}
            >
              {children ?? <Presets />}
              <RecentTimeframes />
            </Flex>
            {/* eslint-disable @typescript-eslint/no-deprecated */}
            <TimeframeSelectorOverlayFooter clearable={clearable} />
          </Flex>
          <DismissButton onDismiss={overlayClose} />
        </FocusScope>
      </OverlayStackingProvider>
    </OverlayContainer>
  );
});

(
  TimeframeSelectorOverlay as typeof TimeframeSelectorOverlay & {
    displayName: string;
  }
).displayName = 'TimeframeSelectorOverlay';
